"use strict";parserFactory.register("mtled-novels.com",()=>new MtledNovelsParser);class MtledNovelsParser extends Parser{constructor(){super()}populateUIImpl(){document.getElementById("removeOriginalRow").hidden=!1}getChapterUrls(e){let r=[...e.querySelectorAll("div.card__body a:not(.list-group-item)")].map(e=>util.hyperLinkToChapter(e));return Promise.resolve(r)}findContent(e){return e.querySelector("div.text_content")}extractTitleImpl(e){return e.querySelector("h1")}customRawDomToContentStep(e,r){this.userPreferences.removeOriginal.value&&util.removeChildElementsMatchingSelector(r,"div[id='raw']")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.profile__img")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.profile__info")]}}